public class Solution {

    private static String fizzbuzz(int number) {

        String[] options = {String.valueOf(number), "Fizz", "Buzz", "FizzBuzz"};


        int fizz = (1 - number % 3) / ((number % 3) + 1);


        int buzz = (1 - number % 5) / ((number % 5) + 1) * 2;


        return options[fizz + buzz];
    }

    public static String fizzbuzz(int[] numbers) {

        String[] results = new String[numbers.length];


        for (int i = 0; i < numbers.length; i++) {
            results[i] = fizzbuzz(numbers[i]);
        }


        return String.join(", ", results);
    }

    public static void main(String[] args) {

        int[] testNumbers = {3, 10, 15, 4};


        String output = fizzbuzz(testNumbers);

        System.out.println(output); 
    }
}

